/**
 * REVENANT V31-F1 — NEW NODE: "Block 3.5: Deterministic P2P Validator"
 * Position: Between "Business Impact Calculator" and "Transition Guard & Schema Validator".
 *
 * Behavior:
 *   - Non-P2P tickets: zero-touch passthrough.
 *   - P2P tickets: strict deterministic validation of phone + amount.
 */

const items = $input.all(); // FIX: System context fetched securely
const returnData = [];

const PHONE_REGEX = /^998\d{9}$/;
const MAX_P2P_AMOUNT_UZS = 50000000; // Bank default ceiling

for (const item of items) {
  const json = item.json;
  const ticket = json.canonical_ticket;

  // Defensive: no ticket payload -> passthrough untouched
  if (!ticket) {
    returnData.push(item);
    continue;
  }

  const intent = ticket.rule_engine && ticket.rule_engine.intent;

  // 1. Not a P2P_TRANSFER ticket -> pass through unchanged
  if (intent !== 'P2P_TRANSFER') {
    returnData.push(item);
    continue;
  }

  // 2. P2P_TRANSFER -> strict deterministic validation
  const errors = [];

  const phone = ticket.text_features && ticket.text_features.extracted_p2p_phone;
  if (!phone || typeof phone !== 'string' || !PHONE_REGEX.test(phone)) {
    errors.push('INVALID_P2P_PHONE');
  }

  // Fallback check: amount might be at root json if missing from canonical_ticket
  const rawAmount = ticket.transaction_amount || json.transaction_amount;
  const amount = Number(rawAmount);
  const amountValid = Number.isFinite(amount) && amount > 0 && amount <= MAX_P2P_AMOUNT_UZS;

  if (!amountValid) {
    errors.push('INVALID_P2P_AMOUNT');
  }

  // 3. Errors found -> block the ticket
  if (errors.length > 0) {
    ticket.ticket_status = 'BLOCKED_VALIDATION';
    ticket.block35_passed = false;
    ticket.block35_report = errors.join(', ');
  } else {
    // 4. Valid -> canonicalize phone and mark success
    ticket.p2p_target_canonical = '+' + phone;
    ticket.block35_passed = true;
    ticket.block35_report = 'P2P_VALIDATION_SUCCESS';
    // Ensure amount is synced cleanly to canonical_ticket for downstream use
    ticket.transaction_amount = amount; 
  }

  json.canonical_ticket = ticket;
  returnData.push({ json });
}

return returnData;

/**
 * REVENANT V31-F1 — "Block 4.3: CBU Response Sanitizer" (HARDENED)
 * Position: After "CBU TTT: Resolve Phone-to-Account" & before "Context Assembler".
 */

const items = $input.all(); // FIX: System context fetched securely
const returnData = [];

// Aggressive Prompt-Injection Defenses
const INJECTION_PATTERN = /ignore|override|system|developer|cmd|exec|must|should/gi;
const HARD_NAME_LIMIT = 50;
const UPSTREAM_TICKET_NODE = 'Block 3.5: Deterministic P2P Validator'; // <-- Adjust to exact node name

function sanitizeAccountHolderName(rawName) {
  if (typeof rawName !== 'string' || rawName.length === 0) {
    return 'UNKNOWN_ACCOUNT_HOLDER';
  }

  let name = rawName;
  // Strip control characters & HTML
  name = name.replace(/[\u0000-\u001F\u007F-\u009F]/g, ' ');
  name = name.replace(/<[^>]*>/g, '');
  // Neutralize markdown & common injection words
  name = name.replace(/[*_`#\[\]()~>|]/g, '');
  name = name.replace(INJECTION_PATTERN, '');
  // Controller fallback: Strip anything non-alphanumeric as final sweep
  name = name.replace(/[^a-zA-Z0-9\s]/g, '');
  // Collapse whitespace and cap length
  name = name.replace(/\s{2,}/g, ' ').trim();

  return name.slice(0, HARD_NAME_LIMIT) || 'UNKNOWN_ACCOUNT_HOLDER';
}

function sanitizeMaskedCard(rawCard) {
  if (typeof rawCard !== 'string') return '';
  return rawCard.replace(/[^0-9*]/g, '').slice(0, 19);
}

for (const item of items) {
  // Account for n8n sometimes nesting HTTP response in .body
  const cbuResponse = item.json.body || item.json || {};

  // Recover canonical_ticket from the upstream node
  let ticket = item.json.canonical_ticket;
  if (!ticket) {
    try {
      ticket = $(UPSTREAM_TICKET_NODE).item.json.canonical_ticket || {};
    } catch (e) {
      ticket = {};
    }
  }

  if (cbuResponse.status === 'SUCCESS') {
    ticket.p2p_resolved_recipient = {
      type: 'CBU_VERIFIED_ACCOUNT',
      legal_name: sanitizeAccountHolderName(cbuResponse.account_holder_name),
      masked_account: sanitizeMaskedCard(cbuResponse.masked_card),
      lookup_verified_at: new Date().toISOString(),
    };
  } else {
    // Controller Directive: Trigger graceful failure if CBU fails
    ticket.p2p_resolved_recipient = { type: "FAILED_LOOKUP" };
    item.json.security_gate = { stop_execution: true, reason: "CBU_RESOLUTION_FAILED" };
  }

  ticket.cbu_lookup_status = cbuResponse.status === 'SUCCESS' ? 'SUCCESS' : 'FAILED';

  // Clean up the output payload so the LLM ONLY sees the sanitized ticket
  item.json = { 
      ...item.json,
      canonical_ticket: ticket,
      ...(item.json.security_gate ? { security_gate: item.json.security_gate } : {})
  };

  returnData.push(item);
}

return returnData;

/**
 * REVENANT V31-F1 — P2P Proposal Builder
 * Builds the stateless token and Telegram confirmation keyboard.
 */
const items = $input.all();
const returnData = [];

function generatePureJSHash(str) {
  let hash = 0x811c9dc5;
  for (let i = 0; i < str.length; i++) {
    hash ^= str.charCodeAt(i);
    hash = Math.imul(hash, 0x01000193);
  }
  return (hash >>> 0).toString(16);
}

for (const item of items) {
  const ticket = item.json.canonical_ticket || {};

  const target_phone = ticket.p2p_target_canonical || 'UNKNOWN_TARGET';
  const amount = ticket.transaction_amount || 0;
  const traceId = ticket.trace_id || 'UNKNOWN_TRACE';

  // 1. Generate Stateless Context Token
  const tokenPayload = {
    trace_id: traceId,
    amount: amount,
    target: target_phone,
    timestamp: Date.now()
  };

  // Base64 encode the payload safely
  const paymentToken = Buffer.from(JSON.stringify(tokenPayload)).toString('base64');
  const tokenSignature = generatePureJSHash(paymentToken);

  // 2. Build Telegram Button with Payload
  const telegramKeyboard = {
    inline_keyboard: [[
      {
        text: '✅ Tasdiqlash (Confirm Transfer)',
        callback_data: `CONFIRM_P2P|${paymentToken}|${tokenSignature}`
      }
    ]]
  };

  // 3. Inject into Advisory output for Telegram node
  if (!item.json.advisory) item.json.advisory = {};
  if (!item.json.advisory.llm_output) item.json.advisory.llm_output = {};

  item.json.advisory.llm_output.transaction_proposal = {
     tool_name: "P2P_TRANSFER",
     telegram_action: telegramKeyboard
  };

  item.json.advisory.llm_output.draft_customer_response = `${target_phone} raqamiga ${amount} UZS o'tkazmani tasdiqlaysizmi?`;

  item.json.canonical_ticket = ticket;
  returnData.push(item);
}

return returnData;

/**
 * REVENANT V31-F1 — "Block 8.0.5: P2P Idempotency Guard" (RECONCILED)
 * Blocks double-spending from Telegram click-spamming at 5,000 TPS.
 */
const items = $input.all();

// Pure-JS 32-bit FNV-1a hash generator (Sandbox Safe)
function generatePureJSHash(str) {
  let hash = 0x811c9dc5;
  for (let i = 0; i < str.length; i++) {
    hash ^= str.charCodeAt(i);
    hash = Math.imul(hash, 0x01000193);
  }
  return (hash >>> 0).toString(16);
}

for (const item of items) {
  const json = item.json;
  const ticket = json.canonical_ticket || {};

  // FIX: Accurately read the fields produced by the Block 3.5 P2P Validator
  const sender_email   = ticket.customer_email || json.source_email;
  const target_phone   = ticket.p2p_target_canonical || json.target_phone;
  const amount_uzs     = ticket.transaction_amount || json.amount_uzs;

  // In the execution block, trace_id acts as the unique approval footprint
  const approval_id    = ticket.trace_id || json.trace_id || json.contract_id;

  // Skip if any critical field is missing
  if (!sender_email || !target_phone || amount_uzs === undefined || approval_id === undefined) {
    json.idempotency_error = "MISSING_CRITICAL_PARAMETERS";
    continue;
  }

  // Concatenate the immutable transaction footprint string
  const footprintString = `${sender_email}${target_phone}${amount_uzs}${approval_id}`;
  const fingerprint = generatePureJSHash(footprintString);

  // Inject fingerprint into the execution ledger parameters
  json.p2p_transaction_fingerprint = fingerprint;

  // Build the exact PostgreSQL INSERT payload with unique fingerprint constraint
  json.idempotency_query_payload = {
    sql_statement: "INSERT INTO bank_p2p_idempotency_ledger (fingerprint, approval_id, created_at) VALUES ($1, $2, NOW());",
    params: [fingerprint, approval_id]
  };
}

return items;

/**
 * REVENANT V31-F1 — "Block 5.2: P2P Execution Trigger"
 * Catches the CONFIRM_P2P callback, verifies the stateless signature, 
 * and routes the approved ticket to the Core Ledger.
 */

const items = $input.all();
const returnData = [];

function fnv1aHash(str) {
  let hash = 0x811c9dc5;
  for (let i = 0; i < str.length; i++) {
    hash ^= str.charCodeAt(i);
    hash = Math.imul(hash, 0x01000193);
  }
  return (hash >>> 0).toString(16);
}

for (const item of items) {
  const callbackData = item.json.callback_data || item.json.body?.callback_query?.data || item.json.callback_query?.data || '';

  if (!callbackData.startsWith('CONFIRM_P2P|')) {
    returnData.push(item);
    continue;
  }

  const parts = callbackData.split('|');
  const base64Payload = parts[1];
  const signature = parts[2];

  if (!base64Payload || !signature) {
    item.json.security_stop = true;
    item.json.error = 'Missing signature payload';
    returnData.push(item);
    continue;
  }

  const computedSignature = fnv1aHash(base64Payload);
  if (computedSignature !== signature) {
    item.json.security_stop = true;
    item.json.error = 'Signature tampering detected';
    returnData.push(item);
    continue;
  }

  // Signature Valid -> Approve for Core Banking Execution
  item.json.status = 'EXECUTE';

  const ticket = item.json.canonical_ticket || {};
  if (!ticket.routing_decision) ticket.routing_decision = {};
  ticket.routing_decision.route = 'P2P_TRANSFER';

  item.json.canonical_ticket = ticket;
  returnData.push(item);
}

return returnData;
